class Solution {
    public boolean[] canMakePalindromeQueries(String s, int[][] queries) {
        int n = s.length();
        int[] freq = new int[26];
        for (char c : s.toCharArray()) {
            freq[c - 'a']++;
        }
        boolean[] answer = new boolean[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int a = queries[i][0], b = queries[i][1], c = queries[i][2], d = queries[i][3];
            int left = (a + b) / 2, right = (c + d) / 2;
            int leftOdd = (a + b) % 2 == 1 ? 1 : 0, rightOdd = (c + d) % 2 == 1 ? 1 : 0;
            int leftDiff = 0, rightDiff = 0;
            for (int j = 0; j < 26; j++) {
                leftDiff += Math.abs(freq[j] - 2 * (left % 2 == 0 ? freq[j] / 2 : (freq[j] + 1) / 2));
                rightDiff += Math.abs(freq[j] - 2 * (right % 2 == 0 ? freq[j] / 2 : (freq[j] + 1) / 2));
            }
            answer[i] = leftDiff <= rightOdd && rightDiff <= leftOdd;
        }
        return answer;
    }
}
